import { CSSTransition, TransitionGroup } from 'react-transition-group';
import './quiz.css'; // Make sure this CSS is imported
import ScreenOne from "./Screenone/ScreenOne"
import ScreenTwo from "./Screentwo/ScreenTwo"
import ScreenThree from "./Screenthree/ScreenThree"
import ScreenFour from "./Screenfour/ScreenFour"
const Quiz = () => {
  const [screen, setScreen] = useState("screen1");
  const [numberOfCurrentScreen, setNumberOfCurrentScreen] = useState(1);
  const [formData, setFormData] = useState({
    name: "",
    email: "",
    phone_number: "",
    gender: "",
    healthProblems: [],
    allergies: [],
    primaryGoal: null,
    otherPrimaryGoal: "",
    achievements: "",
    meetingsPerMonth: null
  });

  const handleInputChange = (field, value) => {
    // Update formData based on field and value
  };

  const changeScreen = (screen, number) => {
    setScreen(screen);
    setNumberOfCurrentScreen(number);
    window.scrollTo(0, 0);
  };

  const submitData = async () => {
    try {
      const response = await fetch("http://localhost:3000/quiz_users", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ quiz_user: formData })
      });

      if (!response.ok) {
        if (response.status === 422) {
          const errorData = await response.json();
          console.error("Validation errors:", errorData);
          alert("Failed to create user: " + JSON.stringify(errorData));
        } else {
          throw new Error(`HTTP error! Status: ${response.status}`);
        }
      } else {
        const result = await response.json();
        console.log("Data submitted successfully:", result);
        alert("User created successfully!");

        // Send email after successful submission
        await fetch("http://localhost:3000/send_email", {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
          },
          body: JSON.stringify({ user: formData })
        });
      }
    } catch (error) {
      console.error("Error submitting data:", error);
      alert("An error occurred. Please try again.");
    }
  };

  const totalScreens = 7; // total number of screens
  const progressPercentage = (numberOfCurrentScreen / totalScreens) * 100;

  return (
    <>
      <div className="progress-background">
        <div className="progress-container">
          <div className="progress-bar-background">
            <div className="progress-bar" style={{ width: `${progressPercentage}%` }}>
              {numberOfCurrentScreen} / {totalScreens}
            </div>
          </div>
        </div>
      </div>
      <TransitionGroup>
        <CSSTransition
          key={screen}
          timeout={500}
          classNames="screen"
        >
          <div className="screen-container">
            {screen === "screen1" && (
              <ScreenOne screen={changeScreen} nmscreen={numberOfCurrentScreen} />
            )}
            {screen === "screen2" && (
              <ScreenTwo
                screen={changeScreen}
                nmscreen={numberOfCurrentScreen}
                formData={formData}
                handleInputChange={handleInputChange}
              />
            )}
            {screen === "screen3" && (
              <ScreenThree
                screen={changeScreen}
                nmscreen={numberOfCurrentScreen}
                formData={formData}
                handleInputChange={handleInputChange}
              />
            )}
            {screen === "screen4" && (
              <ScreenFour
                screen={changeScreen}
                nmscreen={numberOfCurrentScreen}
                formData={formData}
                handleInputChange={handleInputChange}
              />
            )}
            {screen === "screen5" && (
              <ScreenFive
                screen={changeScreen}
                nmscreen={numberOfCurrentScreen}
                formData={formData}
                handleInputChange={handleInputChange}
              />
            )}
            {screen === "screen6" && (
              <ScreenSix
                screen={changeScreen}
                nmscreen={numberOfCurrentScreen}
                formData={formData}
                handleInputChange={handleInputChange}
                submitData={submitData}
              />
            )}
            {screen === "screen7" && <ScreenSeven />}
          </div>
        </CSSTransition>
      </TransitionGroup>
    </>
  );
};

export default Quiz;
